STEPS:

1. Install playwright:
```
cd /root/.openclaw/workspaces2/v4-ecosystem-review/maiy-tech-hub
yarn add -D @playwright/test
npx playwright install chromium --with-deps
```

2. Create tests/e2e/ folder with these test files:

tests/e2e/home.spec.ts:
```typescript
import { test, expect } from '@playwright/test'

test.describe('Home Page', () => {
  test('loads successfully', async ({ page }) => {
    await page.goto('/')
    await expect(page).toHaveTitle(/MAIY Tech Hub/)
  })

  test('shows hero section', async ({ page }) => {
    await page.goto('/')
    await expect(page.locator('h1')).toContainText('Kiến thức CNTT')
  })

  test('navigation links work', async ({ page }) => {
    await page.goto('/')
    await page.click('text=Bài viết')
    await expect(page).toHaveURL(/\/articles/)
  })

  test('dark mode toggle works', async ({ page }) => {
    await page.goto('/')
    const toggle = page.locator('[aria-label="Toggle theme"]')
    if (await toggle.isVisible()) {
      await toggle.click()
      await expect(page.locator('html')).toHaveClass(/dark/)
    }
  })
})
```

tests/e2e/articles.spec.ts:
```typescript
import { test, expect } from '@playwright/test'

test.describe('Articles', () => {
  test('articles listing page loads', async ({ page }) => {
    await page.goto('/articles')
    await expect(page.locator('h1')).toContainText('bài viết')
  })

  test('article detail page loads', async ({ page }) => {
    await page.goto('/articles/binary-search')
    await expect(page.locator('h1')).toBeVisible()
  })

  test('category filter works', async ({ page }) => {
    await page.goto('/articles')
    const ctdlLink = page.locator('a[href*="/articles/category/ctdl"]').first()
    if (await ctdlLink.isVisible()) {
      await ctdlLink.click()
      await expect(page).toHaveURL(/\/articles\/category\/ctdl/)
    }
  })
})
```

tests/e2e/music.spec.ts:
```typescript
import { test, expect } from '@playwright/test'

test.describe('Music Page', () => {
  test('music page loads', async ({ page }) => {
    await page.goto('/music')
    await expect(page.locator('h1')).toContainText('Relaxation Zone')
  })

  test('mood selector changes playlist', async ({ page }) => {
    await page.goto('/music')
    const moodButtons = page.locator('button:has-text("Focus"), button:has-text("Sleep")')
    const count = await moodButtons.count()
    if (count > 0) {
      await moodButtons.first().click()
    }
  })
})
```

tests/e2e/study.spec.ts:
```typescript
import { test, expect } from '@playwright/test'

test.describe('Study Page', () => {
  test('study page loads', async ({ page }) => {
    await page.goto('/study')
    await expect(page.locator('h1')).toContainText('Phòng học')
  })

  test('create room button works', async ({ page }) => {
    await page.goto('/study')
    const createBtn = page.locator('button:has-text("Tạo phòng")')
    if (await createBtn.isVisible()) {
      await createBtn.click()
      await expect(page.locator('text=Phòng học:')).toBeVisible()
    }
  })
})
```

tests/e2e/search.spec.ts:
```typescript
import { test, expect } from '@playwright/test'

test.describe('Search', () => {
  test('search page loads', async ({ page }) => {
    await page.goto('/search')
    await expect(page.locator('h1')).toContainText('Tìm kiếm')
  })

  test('search input is focusable', async ({ page }) => {
    await page.goto('/search')
    const input = page.locator('input[placeholder*="Tìm"]')
    await expect(input).toBeVisible()
    await input.fill('binary search')
  })
})
```

tests/e2e/seo.spec.ts:
```typescript
import { test, expect } from '@playwright/test'

test.describe('SEO', () => {
  test('sitemap is accessible', async ({ page }) => {
    const response = await page.goto('/sitemap.xml')
    expect(response?.status()).toBe(200)
  })

  test('robots.txt is accessible', async ({ page }) => {
    const response = await page.goto('/robots.txt')
    expect(response?.status()).toBe(200)
  })

  test('article has OG tags', async ({ page }) => {
    await page.goto('/articles/binary-search')
    const ogTitle = page.locator('meta[property="og:title"]')
    await expect(ogTitle).toHaveAttribute('content', /.*/)
  })
})
```

3. Create playwright.config.ts:
```typescript
import { defineConfig } from '@playwright/test'

export default defineConfig({
  testDir: './tests/e2e',
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: 'html',
  use: {
    baseURL: 'http://localhost:3000',
    trace: 'on-first-retry',
  },
  webServer: {
    command: 'yarn dev',
    url: 'http://localhost:3000',
    reuseExistingServer: !process.env.CI,
    timeout: 120000,
  },
})
```

Write all files using `write` tool. Then run:
```
cd /root/.openclaw/workspaces2/v4-ecosystem-review/maiy-tech-hub
yarn add -D @playwright/test
npx playwright install chromium
```

Reply with summary when done.

